  const [r3, setR3] = useState(false);
 

  const clkHnd1 = () => {
    setR1(true);
    setR2(false);
    setR3(false);
    
   
};

const clkHnd2 = () => {
    setR1(false);
    setR2(true);
    setR3(false);
   
};

const clkHnd3 = () => {
    setR1(false);
    setR2(false);
    setR3(true);
    
   
};

const clkHnd4 = () => {
    setR1(false);
    setR2(false);
    setR3(false);
   
   
};

  return (
    <div>Gradingw</div>
  )
}

export default Gradingw;
